/**
 * Bootstrap — launches the MCP server from the pre-built bundle.
 *
 * Usage:  node start.js
 *
 * The bundle at dist/index.js is generated by `npm run build` and committed
 * to the repo so that end users never need to run `npm install`.
 * If the bundle is missing, print a clear error — do not silently install.
 */

import { existsSync } from "node:fs";
import { fileURLToPath, pathToFileURL } from "node:url";
import { dirname, resolve } from "node:path";

const __filename = fileURLToPath(import.meta.url);
const projectRoot = dirname(__filename);
const bundlePath = resolve(projectRoot, "dist", "index.js");

if (!existsSync(bundlePath)) {
    console.error(
        "[plan-harness] Pre-built bundle is missing at dist/index.js.\n" +
        "If you are developing the plugin, run:\n" +
        "    cd " + projectRoot + "\n" +
        "    npm install && npm run build\n" +
        "If you are an end user, please report this at the plan-harness repo —\n" +
        "the plugin should ship with dist/ pre-built."
    );
    process.exit(1);
}

// Use a file:// URL so dynamic import accepts an absolute path on every platform
// (Windows ESM loader rejects bare drive-letter paths; macOS/Linux tolerate both).
await import(pathToFileURL(bundlePath).href);
